def update_account_balances(transactions):
    """
    Updates account balances based on a list of transactions.

    Args:
        transactions: A list of dictionaries, where each dictionary represents a transaction with the following keys:
            - account_number: The account number of the transaction.
            - amount: The amount of the transaction.
            - type: The type of transaction (e.g., deposit, withdrawal).

    Returns:
        A dictionary of account balances, where the keys are account numbers and the values are the updated balances.
    """

    account_balances = {}

    for transaction in transactions:
        account_number = transaction['account_number']
        amount = transaction['amount']
        type = transaction['type']

        if account_number not in account_balances:
            account_balances[account_number] = 0

        if type == 'deposit':
            account_balances[account_number] += amount
        elif type == 'withdrawal':
            account_balances[account_number] -= amount

    return account_balances